// Extract key talking points and rapport hooks from LinkedIn profile data
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const profile = data.profile || data;

  const talking_points = [];
  const rapport_hooks = [];

  // Career trajectory analysis
  const experiences = profile.experiences || profile.experience || [];
  if (experiences.length >= 2) {
    const current = experiences[0];
    const previous = experiences[1];
    const trajectory = current.title && previous.title
      ? `Moved from ${previous.title} to ${current.title}`
      : null;
    if (trajectory) talking_points.push({ type: 'career_move', detail: trajectory });
  }

  // Current role tenure
  if (experiences.length > 0 && experiences[0].start_date) {
    const start = new Date(experiences[0].start_date);
    const months = Math.floor((Date.now() - start.getTime()) / (1000 * 60 * 60 * 24 * 30));
    if (months < 6) talking_points.push({ type: 'new_in_role', detail: `Started ${months} months ago - likely evaluating tools` });
    else if (months > 36) talking_points.push({ type: 'established', detail: `${months} months in role - focus on optimization pitch` });
  }

  // Education - shared alma mater potential
  const education = profile.education || [];
  for (const edu of education) {
    if (edu.school || edu.institution) {
      rapport_hooks.push({ type: 'education', school: edu.school || edu.institution, degree: edu.degree || '' });
    }
  }

  // Skills and endorsements - find tech stack overlap
  const skills = profile.skills || [];
  const tech_skills = skills.filter(s => {
    const name = (s.name || s || '').toLowerCase();
    return ['saas', 'cloud', 'api', 'data', 'analytics', 'automation', 'ai', 'machine learning'].some(k => name.includes(k));
  });
  if (tech_skills.length > 0) {
    talking_points.push({ type: 'tech_affinity', skills: tech_skills.slice(0, 5).map(s => s.name || s) });
  }

  // Recent activity themes
  const posts = profile.recent_posts || profile.posts || [];
  const post_topics = posts.slice(0, 5).map(p => p.title || p.text || '').filter(Boolean);
  if (post_topics.length > 0) {
    rapport_hooks.push({ type: 'recent_interests', topics: post_topics.slice(0, 3) });
  }

  // Connections count as social proof indicator
  const connections = profile.connections_count || profile.connections || 0;
  const influence_tier = connections > 5000 ? 'high' : connections > 1000 ? 'medium' : 'growing';

  results.push({
    json: {
      ...data,
      talking_points,
      rapport_hooks,
      prospect_profile: {
        influence_tier,
        connections_count: connections,
        talking_point_count: talking_points.length,
        rapport_hook_count: rapport_hooks.length
      }
    }
  });
}

return results;
